interface User {
  id: number
  name: string
  email: string
}

type Partial<T> = {
  [K in keyof T]?: T[K]
}

type PartialUser = Partial<User>

// TypeScript раскрывает Partial<User> в:
type PartialUser = {
  id?: number      // K='id', T[K]=number
  name?: string    // K='name', T[K]=string
  email?: string   // K='email', T[K]=string
}

// Теперь все поля опциональны
const update: PartialUser = {
  name: 'Новое имя' // id и email можно опустить
}
